#include<bits/stdc++.h>
using namespace std;
int n,m;
int query[10010],ans[10010];
int flag[10010];
bool b[10000010];
vector<pair<int,int>> mp[10010];
int f[10010],t[10010],siz[10010];
int top,cnt,rot;
void getsiz(int x,int fa=-1)
{
    cnt++;
    siz[x]=1;
    for(pair<int,int> i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!flag[v])
        {
            getsiz(v,x);
            siz[x]+=siz[v];
        }
    }
}
void dp(int x,int fa=-1)
{
    f[x]=cnt-siz[x];
    for(pair<int,int> i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!flag[v])
        {
            f[x]=max(f[x],siz[v]);
            dp(v,x);
        }
    }
    if(f[x]<f[rot])
    {
        rot=x;
    }
}
void getdis(int x,int fa,int dis)
{
    t[top++]=dis;
    for(pair<int,int> i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!flag[v])
        {
            getdis(v,x,dis+val);
        }
    }
}
void solve(int x)
{
    cnt=0;
    getsiz(x,x);
    rot=x;
    dp(x,x);
    b[0]=true;
    t[0]=0;
    top=1;
    int p;
    for(auto i:mp[rot])
    {
        int v=i.first,val=i.second;
        if(!flag[v])
        {
            p=top;
            getdis(v,rot,val);
            for(int q=1;q<=m;q++)
            {
                for(int j=p;j<top&&ans[q]==0;j++)
                {
                    if(query[q]>=t[j])
                    {
                        ans[q]=b[query[q]-t[j]];
                    }
                }
            }
            p--;
            while((++p)<top)
            {
                if(t[p]<10000007)
                {
                    b[t[p]]=true;
                }
            }
        }
    }
    while(top--)
    {
        if(t[top]<10000007)
        {
            b[t[top]]=false;
        }
    }
    flag[rot]=1;
    for(auto i:mp[rot])
    {
        int v=i.first,val=i.second;
        if(!flag[v])
        {
            solve(v);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&query[i]);
    }
    solve(1);
    for(int i=1;i<=m;i++)
    {
        if(ans[i])
        {
            printf("AYE\n");
        }
        else
        {
            printf("NAY\n");
        }
    }
    return 0;
}
